{
  name: 'profile',
  description: 'Load an agent profile (shows what would be applied)',
  usage: '[name]',
  async execute(args, ctx) {
    const profileName = args.trim();

    const store = new ProfileStore(ctx.config.projectRoot);

    // No name provided — list available profiles
    if (!profileName) {
      const profiles = await store.list();
      if (profiles.length === 0) {
        console.log(chalk.dim('No profiles found.'));
        console.log(chalk.dim('Create one with: epam profile save <name>'));
        return true;
      }

      console.log(chalk.bold('\nAvailable Profiles:\n'));
      for (const profile of profiles) {
        const sourceTag =
          profile.source === 'local' ? chalk.cyan('[local]') : chalk.dim('[global]');
        const tags =
          profile.tags && profile.tags.length > 0
            ? chalk.dim(` · ${profile.tags.join(', ')}`)
            : '';

        console.log(`  ${chalk.bold(profile.name)} ${sourceTag}${tags}`);
        console.log(`    ${chalk.dim(profile.description || '(no description)')}`);
      }
      console.log();
      console.log(chalk.dim('Use /profile <name> to load a profile'));
      console.log();
      return true;
    }

    // Load the specified profile
    const profile = await store.load(profileName);
    if (!profile) {
      console.log(chalk.red(`Profile '${profileName}' not found.`));
      return true;
    }

    console.log(chalk.bold(`\nLoaded profile: ${profile.name}\n`));
    console.log(`  ${chalk.dim(profile.description || '(no description)')}`);

    const changes: string[] = [];

    if (profile.model) {
      changes.push(`Model: ${chalk.cyan(profile.model)}`);
      // Apply model change
      ctx.onModelChange(profile.model);
    }

    if (profile.maxIterations !== undefined) {
      changes.push(`Max iterations: ${profile.maxIterations}`);
    }

    if (profile.systemPromptAppend) {
      const preview =
        profile.systemPromptAppend.length > 60
          ? profile.systemPromptAppend.slice(0, 60) + '…'
          : profile.systemPromptAppend;
      changes.push(`System prompt append: ${chalk.dim(preview)}`);
    }

    if (profile.tools?.enabled) {
      changes.push(`Tools enabled: ${profile.tools.enabled.join(', ')}`);
    }

    if (profile.tools?.disabled) {
      changes.push(`Tools disabled: ${profile.tools.disabled.join(', ')}`);
    }

    if (changes.length > 0) {
      console.log();
      for (const change of changes) {
        console.log(`  ${change}`);
      }
    }

    console.log();
    console.log(
      chalk.yellow(
        '⚠  Note: Only model changes apply immediately. Other settings require session restart.'
      )
    );
    console.log();
    return true;
  },
},

