import { Command } from 'commander';
import { resolveConfig } from '../../config/ConfigResolver.js';
import { AuthManager } from '../../auth/AuthManager.js';
import { ReadFileTool } from '../../tools/builtin/ReadFile.js';
import { WriteFileTool } from '../../tools/builtin/WriteFile.js';
import { BashTool } from '../../tools/builtin/Bash.js';
import { ListFilesTool } from '../../tools/builtin/ListFiles.js';
import { SearchTool } from '../../tools/builtin/Search.js';
import { FetchUrlTool } from '../../tools/builtin/FetchUrl.js';
import { Repl } from '../repl/Repl.js';
import { PipeWriter } from '../output/PipeWriter.js';
import { AgentRunner } from '../../agent/AgentRunner.js';
import { buildSystemPrompt } from '../../context/ContextBuilder.js';
import { ProviderChain } from '../../providers/ProviderChain.js';
import { getApiKey as getEnvApiKey } from '../../config/EnvVarOverrides.js';
import { resolveProviderSecret } from '../../auth/ProviderCredentialStore.js';
import { detectTier } from '../../billing/TierDetector.js';
import { McpClient } from '../../mcp/McpClient.js';

const VERSION = '0.1.0';

export function createChatCommand(): Command {
  return new Command('chat')
    .description('Start an interactive chat session')
    .option('-m, --model <model>', 'Model to use')
    .option('-p, --provider <provider>', 'Provider to use')
    .action(async (opts) => {
      const config = await resolveConfig({
        model: opts.model,
        provider: opts.provider,
      });

      const authManager = new AuthManager(config.backendUrl);
      const tier = await detectTier();

      // Build provider chain from llmChain config (up to 5 slots)
      const chain = new ProviderChain({
        slots: config.llmChain,
        resolveApiKey: async (providerName: string) => {
          return getEnvApiKey(providerName) ?? await resolveProviderSecret(providerName);
        },
        proxyConfig: (tier === 'pro' || tier === 'enterprise') ? {
          backendUrl: config.backendUrl,
          getAccessToken: () => authManager.getValidToken(),
        } : undefined,
      });
      await chain.initialize();

      // Fallback single provider (used for pipe mode and MemoryCompressor)
      const provider = chain;

      // Initialize MCP client and fetch remote tools
      const mcpClient = new McpClient(config.projectRoot ?? undefined);
      await mcpClient.initialize();
      const mcpTools = mcpClient.getTools();

      const tools = [
        new ReadFileTool(),
        new WriteFileTool(),
        new BashTool(),
        new ListFilesTool(),
        new SearchTool(),
        new FetchUrlTool(),
        ...mcpTools,
      ];

      if (!process.stdin.isTTY) {
        // Pipe mode: read stdin and run once
        const chunks: string[] = [];
        for await (const chunk of process.stdin) {
          chunks.push(chunk.toString());
        }
        const userMessage = chunks.join('').trim();
        if (!userMessage) process.exit(0);

        const systemPrompt = await buildSystemPrompt({
          contextFilePath: config.contextFile,
          systemPromptFile: config.systemPromptFile,
          projectRoot: config.projectRoot,
        });

        const writer = new PipeWriter();
        const runner = new AgentRunner({
          userMessage,
          systemPrompt,
          provider,
          model: config.model,
          tools,
          maxIterations: config.maxIterations,
          autoCompressAt: config.autoCompressAt,
          maxOutputTokens: config.maxOutputTokens,
          dangerousSkipApproval: config.tools.dangerousSkipApproval,
          onTextDelta: delta => writer.write(delta),
        });

        await runner.run();
        writer.finalize();
        return;
      }

      const repl = new Repl({ provider, tools, config, version: VERSION, providerChain: chain, mcpClient });
      await repl.start();
    });
}

import { Command } from 'commander';
import { resolveConfig } from '../../config/ConfigResolver.js';
import { AuthManager } from '../../auth/AuthManager.js';
import { ReadFileTool } from '../../tools/builtin/ReadFile.js';
import { WriteFileTool } from '../../tools/builtin/WriteFile.js';
import { BashTool } from '../../tools/builtin/Bash.js';
import { ListFilesTool } from '../../tools/builtin/ListFiles.js';
import { SearchTool } from '../../tools/builtin/Search.js';
import { FetchUrlTool } from '../../tools/builtin/FetchUrl.js';
import { AgentRunner } from '../../agent/AgentRunner.js';
import { buildSystemPrompt } from '../../context/ContextBuilder.js';
import { ProviderChain } from '../../providers/ProviderChain.js';
import { getApiKey as getEnvApiKey } from '../../config/EnvVarOverrides.js';
import { resolveProviderSecret } from '../../auth/ProviderCredentialStore.js';
import { detectTier } from '../../billing/TierDetector.js';
import { calculateCost } from '../../billing/pricing.js';

async function readStdin(): Promise<string> {
  const chunks: string[] = [];
  for await (const chunk of process.stdin) {
    chunks.push(chunk.toString());
  }
  return chunks.join('').trim();
}

export function createRunCommand(): Command {
  return new Command('run')
    .description('Run a single agent task non-interactively')
    .argument('[prompt]', 'The task to execute (use "-" or omit to read from stdin)')
    .option('-m, --model <model>', 'Model to use')
    .option('-p, --provider <provider>', 'Provider to use')
    .option('--no-tools', 'Disable all tools')
    .option('--json', 'Output result as structured JSON (suppresses streaming text)')
    .action(async (promptArg: string | undefined, opts) => {
      // Resolve the prompt: argument, stdin via "-", or piped stdin when omitted
      let prompt: string;
      if (promptArg === '-' || (promptArg == null && !process.stdin.isTTY)) {
        prompt = await readStdin();
        if (!prompt) {
          process.stderr.write('Error: no prompt provided via stdin\n');
          process.exit(1);
        }
      } else if (promptArg) {
        prompt = promptArg;
      } else {
        process.stderr.write('Error: <prompt> argument required, or pipe input via stdin\n');
        process.exit(1);
      }

      const jsonMode = opts.json === true;
      const config = await resolveConfig({
        model: opts.model,
        provider: opts.provider,
      });

      const authManager = new AuthManager(config.backendUrl);
      const tier = await detectTier();

      const chain = new ProviderChain({
        slots: config.llmChain,
        resolveApiKey: async (providerName: string) => {
          return getEnvApiKey(providerName) ?? await resolveProviderSecret(providerName);
        },
        proxyConfig: (tier === 'pro' || tier === 'enterprise') ? {
          backendUrl: config.backendUrl,
          getAccessToken: () => authManager.getValidToken(),
        } : undefined,
      });
      await chain.initialize();

      const tools = opts.tools
        ? [
            new ReadFileTool(),
            new WriteFileTool(),
            new BashTool(),
            new ListFilesTool(),
            new SearchTool(),
            new FetchUrlTool(),
          ]
        : [];

      const systemPrompt = await buildSystemPrompt({
        contextFilePath: config.contextFile,
        systemPromptFile: config.systemPromptFile,
        projectRoot: config.projectRoot,
      });

      const runner = new AgentRunner({
        userMessage: prompt,
        systemPrompt,
        provider: chain,
        model: config.model,
        tools,
        maxIterations: config.maxIterations,
        autoCompressAt: config.autoCompressAt,
        maxOutputTokens: config.maxOutputTokens,
        dangerousSkipApproval: config.tools.dangerousSkipApproval,
        onTextDelta: jsonMode ? undefined : delta => process.stdout.write(delta),
      });

      const result = await runner.run();

      if (jsonMode) {
        const cost = calculateCost(
          config.model,
          result.usage.inputTokens,
          result.usage.outputTokens,
        );
        const output = {
          result: result.finalResponse,
          model: config.model,
          provider: config.provider,
          usage: {
            inputTokens: result.usage.inputTokens,
            outputTokens: result.usage.outputTokens,
            totalTokens: result.usage.inputTokens + result.usage.outputTokens,
          },
          cost_usd: Math.round(cost * 10000) / 10000,
          toolCallCount: result.toolCallCount,
          iterations: result.iterations,
        };
        process.stdout.write(JSON.stringify(output, null, 2) + '\n');
      } else {
        if (process.stdout.isTTY) process.stdout.write('\n');
      }
    });
}

import { Command } from 'commander';
import chalk from 'chalk';
import prompts from 'prompts';
import { resolveConfig } from '../../config/ConfigResolver.js';
import { ProfileStore } from '../../agent/profiles/ProfileStore.js';
import type { Profile } from '../../agent/profiles/types.js';

export function createProfileCommand(): Command {
  const cmd = new Command('profile')
    .description('Manage agent profiles (saved configurations)')
    .action(() => {
      cmd.help();
    });

  cmd
    .command('list')
    .description('List all available profiles')
    .action(async () => {
      try {
        const config = await resolveConfig();
        const store = new ProfileStore(config.projectRoot);
        const profiles = await store.list();

        if (profiles.length === 0) {
          console.log(chalk.dim('No profiles found.'));
          console.log();
          console.log(chalk.dim('Create a profile with: epam profile save <name>'));
          return;
        }

        console.log(chalk.bold('\nAvailable Profiles:\n'));

        for (const profile of profiles) {
          const sourceTag =
            profile.source === 'local'
              ? chalk.cyan('[local]')
              : chalk.dim('[global]');
          const tags = profile.tags && profile.tags.length > 0
            ? chalk.dim(` · ${profile.tags.join(', ')}`)
            : '';

          console.log(`  ${chalk.bold(profile.name)} ${sourceTag}${tags}`);
          console.log(`    ${chalk.dim(profile.description || '(no description)')}`);

          const details: string[] = [];
          if (profile.model) details.push(`model: ${profile.model}`);
          if (profile.maxIterations) details.push(`maxIterations: ${profile.maxIterations}`);
          if (profile.tools?.enabled) details.push(`tools: ${profile.tools.enabled.length} enabled`);
          if (profile.tools?.disabled) details.push(`tools: ${profile.tools.disabled.length} disabled`);

          if (details.length > 0) {
            console.log(`    ${chalk.dim(details.join(' · '))}`);
          }
          console.log();
        }
      } catch (error) {
        process.stderr.write(
          `Error: ${error instanceof Error ? error.message : String(error)}\n`
        );
        process.exit(1);
      }
    });

  cmd
    .command('load <name>')
    .description('Show what would be loaded from a profile (non-interactive)')
    .action(async (name: string) => {
      try {
        const config = await resolveConfig();
        const store = new ProfileStore(config.projectRoot);
        const profile = await store.load(name);

        if (!profile) {
          console.log(chalk.red(`Profile '${name}' not found.`));
          process.exit(1);
        }

        console.log(chalk.bold(`\nProfile: ${profile.name}\n`));
        console.log(`  Description:  ${chalk.dim(profile.description || '(none)')}`);
        console.log(`  Source:       ${profile.source === 'local' ? chalk.cyan('local') : chalk.dim('global')}`);
        console.log(`  File:         ${chalk.dim(profile.filePath)}`);

        if (profile.model) {
          console.log(`  Model:        ${chalk.cyan(profile.model)}`);
        }
        if (profile.maxIterations) {
          console.log(`  Max Iter:     ${profile.maxIterations}`);
        }
        if (profile.systemPromptAppend) {
          const preview = profile.systemPromptAppend.slice(0, 80);
          const suffix = profile.systemPromptAppend.length > 80 ? '…' : '';
          console.log(`  Sys Append:   ${chalk.dim(preview + suffix)}`);
        }
        if (profile.tools?.enabled) {
          console.log(`  Tools:        ${profile.tools.enabled.join(', ')}`);
        }
        if (profile.tools?.disabled) {
          console.log(`  Disabled:     ${profile.tools.disabled.join(', ')}`);
        }
        if (profile.tags && profile.tags.length > 0) {
          console.log(`  Tags:         ${profile.tags.join(', ')}`);
        }

        console.log();
        console.log(chalk.dim('To use this profile in a REPL session: /profile ' + name));
        console.log();
      } catch (error) {
        process.stderr.write(
          `Error: ${error instanceof Error ? error.message : String(error)}\n`
        );
        process.exit(1);
      }
    });

  cmd
    .command('save <name>')
    .description('Save a new profile (interactive)')
    .option('-d, --description <text>', 'Profile description')
    .option('-m, --model <model>', 'Model override')
    .option('--max-iterations <n>', 'Max iterations override')
    .option('--tags <tags>', 'Comma-separated tags')
    .option('--global', 'Save to global profiles instead of project-local')
    .action(
      async (
        name: string,
        options: {
          description?: string;
          model?: string;
          maxIterations?: string;
          tags?: string;
          global?: boolean;
        }
      ) => {
        try {
          const config = await resolveConfig();
          const store = new ProfileStore(config.projectRoot);

          // Check if profile already exists
          const existing = await store.load(name);
          if (existing) {
            const response = await prompts({
              type: 'confirm',
              name: 'overwrite',
              message: `Profile '${name}' already exists. Overwrite?`,
              initial: false,
            });

            if (!response.overwrite) {
              console.log(chalk.dim('Cancelled.'));
              return;
            }
          }

          // Prompt for missing fields
          let description = options.description;
          if (!description) {
            const response = await prompts({
              type: 'text',
              name: 'description',
              message: 'Description:',
              initial: existing?.description ?? '',
            });
            description = response.description || '';
          }

          const profile: Profile = {
            name,
            description: description || '',
            model: options.model,
            maxIterations: options.maxIterations ? parseInt(options.maxIterations, 10) : undefined,
            tags: options.tags ? options.tags.split(',').map(t => t.trim()) : undefined,
          };

          const location = options.global ? 'global' : 'local';
          const filePath = await store.save(profile, location);

          console.log(chalk.green(`Profile '${name}' saved to ${location}`));
          console.log(chalk.dim(filePath));
          console.log();
        } catch (error) {
          process.stderr.write(
            `Error: ${error instanceof Error ? error.message : String(error)}\n`
          );
          process.exit(1);
        }
      }
    );

  cmd
    .command('delete <name>')
    .description('Delete a profile')
    .option('--yes', 'Skip confirmation prompt')
    .action(async (name: string, options: { yes?: boolean }) => {
      try {
        const config = await resolveConfig();
        const store = new ProfileStore(config.projectRoot);

        // Check if profile exists
        const profile = await store.load(name);
        if (!profile) {
          console.log(chalk.yellow(`Profile '${name}' not found.`));
          return;
        }

        // Confirm deletion
        if (!options.yes) {
          console.log(
            chalk.dim(`Profile: ${profile.name} (${profile.source})`)
          );
          console.log(chalk.dim(`File: ${profile.filePath}`));

          const response = await prompts({
            type: 'confirm',
            name: 'confirm',
            message: `Delete this profile?`,
            initial: false,
          });

          if (!response.confirm) {
            console.log(chalk.dim('Cancelled.'));
            return;
          }
        }

        const result = await store.delete(name);

        if (result.notFound) {
          console.log(chalk.yellow(`Profile '${name}' not found.`));
        } else {
          console.log(chalk.green(`Deleted ${result.deleted.length} file(s):`));
          for (const file of result.deleted) {
            console.log(chalk.dim(`  ${file}`));
          }
        }
        console.log();
      } catch (error) {
        process.stderr.write(
          `Error: ${error instanceof Error ? error.message : String(error)}\n`
        );
        process.exit(1);
      }
    });

  return cmd;
}

import path from 'path';
import { appendLine, readLines, ensureDir } from '../utils/fs.js';
import type { Decision } from './types.js';

export class DecisionStore {
  private decisionsPath: string;

  constructor(projectRoot: string) {
    this.decisionsPath = path.join(projectRoot, '.epam', 'decisions.jsonl');
  }

  /**
   * Add a new decision record with auto-generated ID
   */
  async add(decision: Omit<Decision, 'id' | 'createdAt'>): Promise<Decision> {
    const existingDecisions = await this.list();
    const nextId = this.generateNextId(existingDecisions);

    const newDecision: Decision = {
      ...decision,
      id: nextId,
      createdAt: new Date().toISOString(),
    };

    await ensureDir(path.dirname(this.decisionsPath));
    await appendLine(this.decisionsPath, newDecision);

    return newDecision;
  }

  /**
   * List all decisions
   */
  async list(): Promise<Decision[]> {
    const lines = await readLines(this.decisionsPath);
    return lines
      .map(line => {
        try {
          return JSON.parse(line) as Decision;
        } catch {
          return null;
        }
      })
      .filter((d): d is Decision => d !== null);
  }

  /**
   * Search decisions by keyword (case-insensitive match on title, description, tags)
   */
  async search(query: string): Promise<Decision[]> {
    const allDecisions = await this.list();
    const lowerQuery = query.toLowerCase();

    return allDecisions.filter(decision => {
      const titleMatch = decision.title.toLowerCase().includes(lowerQuery);
      const descriptionMatch = decision.description?.toLowerCase().includes(lowerQuery) ?? false;
      const tagsMatch = decision.tags.some(tag => tag.toLowerCase().includes(lowerQuery));

      return titleMatch || descriptionMatch || tagsMatch;
    });
  }

  /**
   * Generate next sequential ID (DEC-001, DEC-002, etc.)
   */
  private generateNextId(existingDecisions: Decision[]): string {
    if (existingDecisions.length === 0) {
      return 'DEC-001';
    }

    // Extract numeric part from IDs and find max
    const numbers = existingDecisions
      .map(d => {
        const match = d.id.match(/^DEC-(\d+)$/);
        return match ? parseInt(match[1], 10) : 0;
      })
      .filter(n => n > 0);

    const maxNumber = Math.max(0, ...numbers);
    const nextNumber = maxNumber + 1;

    return `DEC-${String(nextNumber).padStart(3, '0')}`;
  }
}

