private buildSlashContext(config: ResolvedConfig): SlashCommandContext {
  return {
    config,
    currentModel: this.currentModel,
    sessionTurnCount: this.session.turns.length,
    messages: this.messages,
    tokenCount: this.messages.reduce((sum, m) => {
      const text =
        typeof m.content === 'string' ? m.content : JSON.stringify(m.content);
      return sum + Math.ceil(text.length / 4);
    }, 0),
    contextFilePath: config.contextFile,
    totalInputTokens: this.budgetGuard.inputTokens,
    totalOutputTokens: this.budgetGuard.outputTokens,
    budgetGuard: this.budgetGuard,
    tools: this.options.tools,
    toolRunner: this.toolRunner,

    onModelChange: model => {
      this.currentModel = model;
      this.budgetGuard.setModel(model);
    },

    onClear: () => {
      this.messages = [];
    },

    onCompact: async () => {
      this.messages = await compressHistory(
        this.messages,
        this.options.provider,
        this.currentModel
      );
    },

    // Remove last user+assistant pair
    onRewind: () => {
      // Walk back from end removing the last assistant then last user message
      let removed = 0;
      while (this.messages.length > 0 && removed < 2) {
        const last = this.messages[this.messages.length - 1];
        if (last.role === 'assistant' || last.role === 'user') {
          this.messages.pop();
          removed++;
        } else {
          break;
        }
      }
      // Also remove any trailing tool messages
      while (
        this.messages.length > 0 &&
        this.messages[this.messages.length - 1].role === 'tool'
      ) {
        this.messages.pop();
      }
    },

    // Load a past session's messages into current context
    onResume: async (sessionId: string) => {
      const loaded = await loadSession(sessionId, config.projectRoot);
      if (!loaded) return { success: false, turnCount: 0 };

      // Reconstruct messages from stored turns
      const reconstructed: Message[] = [];
      for (const turn of loaded.turns) {
        reconstructed.push({ role: 'user', content: turn.userMessage });
        reconstructed.push({ role: 'assistant', content: turn.assistantResponse });
      }

      this.messages = reconstructed;

      // Carry forward token counts from resumed session into budget guard
      const resumedInput = loaded.turns.reduce((s, t) => s + t.usage.inputTokens, 0);
      const resumedOutput = loaded.turns.reduce((s, t) => s + t.usage.outputTokens, 0);
      this.budgetGuard.loadTokens(resumedInput, resumedOutput);

      return { success: true, turnCount: loaded.turns.length };
    },

    providerChain: this.options.providerChain,
    mcpClient: this.options.mcpClient,

    onChainUpdate: async (slots: LLMChainSlot[]) => {
      const chain = this.options.providerChain;
      if (!chain) return;
      // Re-initialize the chain with new slots is not trivially mutable —
      // update the config so /chain status reflects new priority, and note it will take
      // effect on next session (ProviderChain is immutable after construction).
      // For live switching: update activeSlotIndex by resetting health of new slots.
      chain.getHealth().resetAll();
      // Update the config reference so /chain shows the right order
      config.llmChain = slots;
      this.currentModel = slots[0]?.model ?? this.currentModel;
    },

    onPlanMode: async (userRequest: string) => {
      await this.handlePlanMode(userRequest);
    },
  };
}

/**
 * Handle /plan command: generate plan, get approval, execute
 */
private async handlePlanMode(userRequest: string): Promise<void> {
  const { provider, tools, config } = this.options;

  // Generate the plan
  const plan = await PlanMode.generatePlan(userRequest, {
    provider,
    tools,
    model: this.currentModel,
    systemPrompt: this.systemPrompt,
    history: this.messages,
    budgetGuard: this.budgetGuard,
    projectRoot: config.projectRoot,
  });

  if (!plan) {
    return; // Generation failed, error already shown
  }

  // Display the plan
  PlanMode.displayPlan(plan);

  // Get user approval
  const approval = await PlanMode.getUserApproval(plan, config.projectRoot);

  if (approval === 'rejected') {
    console.log(chalk.dim('\nPlan cancelled.\n'));
    return;
  }

  // Save the approved plan
  const savedPath = await PlanMode.savePlan(plan, config.projectRoot);
  console.log(chalk.dim(`\nPlan saved to: ${savedPath}\n`));

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { buildSystemPrompt } from '../../../src/context/ContextBuilder.js';
import type { Constraint } from '../../../src/constraints/types.js';
import * as ContextLoader from '../../../src/context/ContextLoader.js';

vi.mock('../../../src/context/ContextLoader.js', () => ({
  loadContextFile: vi.fn(),
}));

vi.mock('../../../src/decisions/DecisionStore.js', () => ({
  DecisionStore: vi.fn().mockImplementation(() => ({
    list: vi.fn().mockResolvedValue([]),
  })),
}));

describe('buildSystemPrompt', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    vi.mocked(ContextLoader.loadContextFile).mockResolvedValue(null);
  });

  it('should inject block-severity constraints at the top', async () => {
    const blockConstraints: Constraint[] = [
      {
        id: 'c1',
        rule: 'Never use eval()',
        severity: 'block',
        createdBy: 'admin',
        expiresAt: '2026-12-31T23:59:59Z',
      },
      {
        id: 'c2',
        rule: 'Always validate input',
        severity: 'block',
        createdBy: 'admin',
        expiresAt: '2026-12-31T23:59:59Z',
      },
    ];

    const systemPrompt = await buildSystemPrompt({
      contextFilePath: '.epam/context.md',
      blockConstraints,
    });

    expect(systemPrompt).toContain('[CONSTRAINTS — MUST FOLLOW]');
    expect(systemPrompt).toContain('- Never use eval()');
    expect(systemPrompt).toContain('- Always validate input');

    // Block constraints should appear before project context
    const blockIndex = systemPrompt.indexOf('[CONSTRAINTS — MUST FOLLOW]');
    const contextIndex = systemPrompt.indexOf('## Project Context');
    expect(blockIndex).toBeLessThan(contextIndex === -1 ? systemPrompt.length : contextIndex);
  });

  it('should inject warn-severity constraints at the bottom', async () => {
    const warnConstraints: Constraint[] = [
      {
        id: 'c1',
        rule: 'Prefer const over let',
        severity: 'warn',
        createdBy: 'admin',
        expiresAt: '2026-12-31T23:59:59Z',
      },
    ];

    const systemPrompt = await buildSystemPrompt({
      contextFilePath: '.epam/context.md',
      warnConstraints,
    });

    expect(systemPrompt).toContain('[ADVISORY CONSTRAINTS]');
    expect(systemPrompt).toContain('- Prefer const over let');

    // Warn constraints should appear at the end
    const warnIndex = systemPrompt.indexOf('[ADVISORY CONSTRAINTS]');
    expect(warnIndex).toBeGreaterThan(0);
  });

  it('should inject both block and warn constraints in correct order', async () => {
    const blockConstraints: Constraint[] = [
      {
        id: 'c1',
        rule: 'Block rule',
        severity: 'block',
        createdBy: 'admin',
        expiresAt: '2026-12-31T23:59:59Z',
      },
    ];

    const warnConstraints: Constraint[] = [
      {
        id: 'c2',
        rule: 'Warn rule',
        severity: 'warn',
        createdBy: 'admin',
        expiresAt: '2026-12-31T23:59:59Z',
      },
    ];

    const systemPrompt = await buildSystemPrompt({
      contextFilePath: '.epam/context.md',
      blockConstraints,
      warnConstraints,
    });

    const blockIndex = systemPrompt.indexOf('[CONSTRAINTS — MUST FOLLOW]');
    const warnIndex = systemPrompt.indexOf('[ADVISORY CONSTRAINTS]');

    expect(blockIndex).toBeGreaterThan(-1);
    expect(warnIndex).toBeGreaterThan(-1);
    expect(blockIndex).toBeLessThan(warnIndex);
  });

  it('should not include constraint sections when no constraints provided', async () => {
    const systemPrompt = await buildSystemPrompt({
      contextFilePath: '.epam/context.md',
    });

    expect(systemPrompt).not.toContain('[CONSTRAINTS — MUST FOLLOW]');
    expect(systemPrompt).not.toContain('[ADVISORY CONSTRAINTS]');
  });

  it('should not include constraint sections when empty arrays provided', async () => {
    const systemPrompt = await buildSystemPrompt({
      contextFilePath: '.epam/context.md',
      blockConstraints: [],
      warnConstraints: [],
    });

    expect(systemPrompt).not.toContain('[CONSTRAINTS — MUST FOLLOW]');
    expect(systemPrompt).not.toContain('[ADVISORY CONSTRAINTS]');
  });
});

